  function makeQuestion(row, variant, difficulty) {
    const [objective, label, skill, tag, correct, distractors, prompts] = row;
    const options = [correct, ...distractors];
    return {
      id: nextId++, sourceGame: "strategyDesk", q: prompts[variant], options,
      a: 0, tag, type: variant === 0 ? "definition" : variant === 1 ? "application" : "strategy",
      objective, difficulty, conceptCluster: `${objective}_strategy_desk`,
      primarySkill: skill, secondarySkills: [], repairSkill: skill,
      commonError: `misapplies_${skill}`,
      feedback: correct
    };
  }

  rows.forEach(row => {
    objectiveLabels[row[0]] = row[1];
    byObjective[row[0]] = [0, 1, 2].map(variant => makeQuestion(row, variant, "standard"));
    standard.push(...byObjective[row[0]]);
  });

